import React from 'react';
import TabelaRelatorioEconomico from '../components/TabelaRelatorioEconomico';
import MenuLateral from '../components/MenuLateral';

const anoAtual = new Date().getFullYear();
const dataLinhas = [
  `31/03/${anoAtual}`,
  `31/03/${anoAtual}`,
  `31/03/${anoAtual}`,
  `30/06/${anoAtual}`,
  `30/06/${anoAtual}`,
  `30/06/${anoAtual}`,
];

export default function RelatorioPrimeiroSemestre() {
  // Bloqueio de acesso direto
  React.useEffect(() => {
    if (sessionStorage.getItem('acessoRelatorioPrimeiroSemestre') !== 'ok') {
      window.location.href = '/';
    } else {
      sessionStorage.removeItem('acessoRelatorioPrimeiroSemestre');
    }
  }, []);
  let razaoSocial = '';
  try {
    const salvo = localStorage.getItem('clienteSelecionado');
    if (salvo) {
      const obj = JSON.parse(salvo);
      if (obj.razaoSocial) razaoSocial = obj.razaoSocial;
    }
  } catch {}
  return (
    <div style={{display:'flex'}}>
      <MenuLateral />
      <div style={{marginLeft:210, width:'100%'}}>
        <TabelaRelatorioEconomico datasPadrao={dataLinhas} razaoSocial={razaoSocial} semestre="SEM1" ano={anoAtual} />
      </div>
    </div>
  );
}
